import { useMemo, useState, useEffect } from 'react';
import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';
import { spaces, cities, types } from '../data/spaces';
import SpaceCard from '../components/SpaceCard';
import MapView from '../components/MapView';
import Filters from '../components/Filters';

function useFavorites() {
  const [fav, setFav] = useState(() => {
    try {
      const raw = localStorage.getItem('wn:favorites');
      return raw ? JSON.parse(raw) : [];
    } catch {
      return [];
    }
  });
  useEffect(() => {
    localStorage.setItem('wn:favorites', JSON.stringify(fav));
  }, [fav]);
  const toggle = (id) => setFav((prev) => (prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]));
  return { favorites: fav, toggle };
}

export default function Search() {
  const [filterValues, setFilterValues] = useState({ city: '', type: '', minPrice: '', maxPrice: '' });
  const { favorites, toggle } = useFavorites();
  const [sortBy, setSortBy] = useState('relevance');
  const [showMap, setShowMap] = useState(false);
  const [homeCity, setHomeCity] = useState(() => {
    try {
      return localStorage.getItem('wn:homeCity') || '';
    } catch { return ''; }
  });
  useEffect(() => {
    localStorage.setItem('wn:homeCity', homeCity);
  }, [homeCity]);

  const filtered = useMemo(() => {
    let result = spaces.filter((s) => {
      if (filterValues.city && s.city !== filterValues.city) return false;
      if (filterValues.type && s.type !== filterValues.type) return false;
      if (filterValues.minPrice && s.pricePerDay < Number(filterValues.minPrice)) return false;
      if (filterValues.maxPrice && s.pricePerDay > Number(filterValues.maxPrice)) return false;
      return true;
    });
    if (sortBy === 'price-asc') result = [...result].sort((a, b) => a.pricePerDay - b.pricePerDay);
    if (sortBy === 'price-desc') result = [...result].sort((a, b) => b.pricePerDay - a.pricePerDay);
    if (sortBy === 'rating-desc') result = [...result].sort((a, b) => b.rating - a.rating);
    return result;
  }, [filterValues, sortBy]);

  const commuteFor = (s) => {
    if (!homeCity) return undefined;
    const same = s.city === homeCity;
    const min = same ? 15 : 45;
    const max = same ? 35 : 90;
    return Math.floor(Math.random() * (max - min + 1)) + min;
  };

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <main className="flex-1">
        {/* Hero Section - Image Background */}
        <section className="relative overflow-hidden min-h-[60vh]">
          {/* Image Background */}
          <div className="absolute inset-0">
            <img 
              src="/Home_page.jpg" 
              alt="Explore Workspaces" 
              className="w-full h-full object-cover"
              onError={(e) => {
                e.target.style.display = 'none';
                e.target.parentElement.classList.add('bg-gradient-to-br', 'from-indigo-950', 'via-blue-950', 'to-indigo-950');
              }}
            />
          </div>
          
          {/* Dark Overlay for Text Readability */}
          <div className="absolute inset-0 bg-gradient-to-b from-black/60 via-black/40 to-black/50"></div>
          
          {/* Subtle Color Overlay */}
          <div className="absolute inset-0 bg-gradient-to-br from-indigo-950/30 via-blue-950/20 to-indigo-950/30"></div>
          
          {/* Diagonal Cut */}
          {/* <div className="absolute bottom-0 left-0 w-full h-24 bg-white transform skew-y-[-1deg] origin-bottom z-10"></div> */}
          
          <div className="relative w-full px-6 md:px-12 lg:px-16 pt-16 pb-20">
            <div className="flex items-start gap-6 mb-8">
              <div className="text-[100px] md:text-[150px] font-black text-white/5 leading-none">01</div>
              <div className="flex-1">
                <h1 className="text-4xl md:text-6xl font-black text-white mb-3">
                  Explore <span className="text-sky-400">Workspaces</span>
                </h1>
                <p className="text-xl text-blue-200">Find the perfect space for your team</p>
              </div>
            </div>
            
            <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-6">
              <div className="flex items-center gap-3 px-5 py-3 bg-white/10 backdrop-blur-sm border-2 border-white/20 rounded-xl">
                <div className="w-10 h-10 rounded-lg bg-gradient-to-br from-sky-500 to-blue-600 flex items-center justify-center shadow-lg">
                  <span className="text-white font-black text-lg">{filtered.length}</span>
                </div>
                <span className="text-white font-bold">results found</span>
              </div>
              
              <div className="flex items-center gap-3 flex-wrap">
                <select
                  className="h-12 px-5 rounded-xl border-2 border-white/20 bg-white/10 backdrop-blur-sm text-white font-medium focus:outline-none focus:border-sky-400"
                  value={homeCity}
                  onChange={(e) => setHomeCity(e.target.value)}
                >
                  <option value="" className="text-slate-900">Commute from</option>
                  {cities.map((c) => (
                    <option key={c} value={c} className="text-slate-900">{c}</option>
                  ))}
                </select>
                <select
                  className="h-12 px-5 rounded-xl border-2 border-white/20 bg-white/10 backdrop-blur-sm text-white font-medium focus:outline-none focus:border-sky-400"
                  value={sortBy}
                  onChange={(e) => setSortBy(e.target.value)}
                >
                  <option value="relevance" className="text-slate-900">Sort: Relevance</option>
                  <option value="price-asc" className="text-slate-900">Price: Low to High</option>
                  <option value="price-desc" className="text-slate-900">Price: High to Low</option>
                  <option value="rating-desc" className="text-slate-900">Rating: High to Low</option>
                </select>
                <button
                  className={`h-12 px-6 rounded-xl border-2 font-bold transition-all duration-200 ${showMap ? 'border-sky-400 bg-gradient-to-r from-sky-500 to-blue-600 text-white' : 'border-white/20 bg-white/10 backdrop-blur-sm text-white hover:bg-white/20'}`}
                  onClick={() => setShowMap(!showMap)}
                >
                  {showMap ? 'List' : 'Map'}
                </button>
              </div>
            </div>
          </div>
        </section>

        <section className="w-full px-6 md:px-12 lg:px-16 py-8">
          <div className="md:sticky md:top-20 z-10 bg-white rounded-2xl p-6 border-2 border-slate-200 shadow-xl">
            <Filters cities={cities} types={types} values={filterValues} onChange={setFilterValues} />
          </div>

          {!showMap ? (
            <div className="mt-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filtered.length === 0 ? (
                <div className="col-span-full py-16 text-center">
                  <div className="w-16 h-16 mx-auto rounded-full bg-gray-100 flex items-center justify-center mb-4">
                    <svg className="w-8 h-8 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                  </div>
                  <h3 className="text-lg font-semibold text-gray-900 mb-2">No spaces found</h3>
                  <p className="text-gray-600">Try adjusting your filters to see more results.</p>
                </div>
              ) : (
                filtered.map((s) => (
                  <SpaceCard key={s.id} space={s} onToggleFavorite={toggle} isFavorite={favorites.includes(s.id)} commuteMins={commuteFor(s)} />
                ))
              )}
            </div>
          ) : (
            <div className="mt-6 rounded-2xl overflow-hidden border border-gray-100 shadow-lg">
              <MapView spaces={filtered} />
            </div>
          )}
        </section>
      </main>
      <Footer />
    </div>
  );
}
